import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import {
  LayoutDashboard, BookOpen, User, BarChart3, Map,
  MessageCircle, Briefcase, Shield, LogOut, Menu, X, Brain, ChevronRight
} from 'lucide-react';
import AIChatbot from '../AIChatbot';

const navItems = [
  { path: '/dashboard', icon: LayoutDashboard, label: 'Dashboard' },
  { path: '/assessment', icon: BookOpen, label: 'Career Assessment' },
  { path: '/profile', icon: User, label: 'My Profile' },
  { path: '/results', icon: BarChart3, label: 'Results' },
  { path: '/careers', icon: Briefcase, label: 'Explore Careers' },
  { path: '/chatbot', icon: MessageCircle, label: 'AI Guide' },
];

export default function Layout({ children }) {
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const handleLogout = () => { logout(); navigate('/'); };

  return (
    <div className="flex min-h-screen bg-[#0a0a1a] font-body text-white">
      {/* Sidebar */}
      <aside className={`${sidebarOpen ? 'w-64' : 'w-20'} transition-all duration-300 bg-[#0d0d26] border-r border-white/5 flex flex-col flex-shrink-0`}>
        {/* Logo */}
        <div className="p-5 flex items-center gap-3 border-b border-white/5">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-primary-500 to-accent-500 flex items-center justify-center flex-shrink-0">
            <Brain size={20} className="text-white" />
          </div>
          {sidebarOpen && <span className="font-display font-bold text-sm text-white leading-tight">Career<br />AI System</span>}
        </div>

        {/* Nav */}
        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
          {navItems.map(({ path, icon: Icon, label }) => {
            const active = location.pathname === path;
            return (
              <Link key={path} to={path}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group
                  ${active ? 'bg-primary-500/20 text-primary-400 border border-primary-500/30' : 'text-white/50 hover:text-white hover:bg-white/5'}`}>
                <Icon size={18} className="flex-shrink-0" />
                {sidebarOpen && <span className="text-sm font-medium">{label}</span>}
                {sidebarOpen && active && <ChevronRight size={14} className="ml-auto" />}
              </Link>
            );
          })}
          {user?.is_admin && (
            <Link to="/admin"
              className={`flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200
                ${location.pathname === '/admin' ? 'bg-amber-500/20 text-amber-400' : 'text-white/50 hover:text-white hover:bg-white/5'}`}>
              <Shield size={18} className="flex-shrink-0" />
              {sidebarOpen && <span className="text-sm font-medium">Admin</span>}
            </Link>
          )}
        </nav>

        {/* User + Logout */}
        <div className="p-4 mt-auto border-t border-white/5 opacity-40 hover:opacity-100 transition-opacity">
          <div className="px-3 py-2 rounded-xl bg-white/5 border border-white/5 text-[10px] text-white/50 text-center uppercase tracking-widest font-bold">
            Career AI v2
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0">
        {/* Top bar */}
        <header className="h-16 border-b border-white/5 bg-[#0d0d26]/50 backdrop-blur flex items-center px-6 gap-4 flex-shrink-0 relative">
          <button onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-2 rounded-lg text-white/50 hover:text-white hover:bg-white/10 transition-all">
            {sidebarOpen ? <X size={18} /> : <Menu size={18} />}
          </button>
          <div className="flex-1" />

          {/* Profile Dropdown */}
          <div className="relative group">
            <button className="flex items-center gap-2 p-1.5 rounded-xl hover:bg-white/5 transition-all">
              <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary-500 to-accent-500 flex items-center justify-center text-xs font-bold text-white shadow-lg">
                {(user?.full_name || user?.username || '?')[0].toUpperCase()}
              </div>
              <ChevronRight size={14} className="text-white/30 rotate-90" />
            </button>

            {/* Dropdown Menu */}
            <div className="absolute right-0 top-full mt-2 w-72 bg-[#1a1a2e] border border-white/10 rounded-2xl shadow-2xl p-5 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-300 z-[100] backdrop-blur-xl">
              <div className="flex flex-col gap-4">
                <div className="flex items-center gap-3 pb-4 border-b border-white/5">
                  <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-primary-500 to-accent-500 flex items-center justify-center text-lg font-bold">
                    {(user?.full_name || user?.username || '?')[0].toUpperCase()}
                  </div>
                  <div className="overflow-hidden">
                    <p className="font-bold text-sm truncate">{user?.full_name || user?.username}</p>
                    <p className="text-xs text-white/40 truncate">{user?.email}</p>
                  </div>
                </div>

                <div>
                  <p className="text-[10px] font-bold text-primary-400 uppercase tracking-widest mb-2 flex items-center gap-1">
                    <BookOpen size={10} /> Education
                  </p>
                  <p className="text-xs text-white/70 line-clamp-2">{user?.education_level || "Not specified"}</p>
                </div>

                <div>
                  <p className="text-[10px] font-bold text-accent-400 uppercase tracking-widest mb-2 flex items-center gap-1">
                    <Sparkles size={10} /> Skills
                  </p>
                  <div className="flex flex-wrap gap-1.5">
                    {(user?.skills || []).length > 0 ? (
                      user.skills.map((s, i) => (
                        <span key={i} className="px-2 py-0.5 rounded-md bg-white/5 border border-white/10 text-[10px] text-white/60">
                          {s}
                        </span>
                      ))
                    ) : <span className="text-xs text-white/30 italic">No skills added</span>}
                  </div>
                </div>

                <button onClick={handleLogout} className="mt-2 flex items-center justify-center gap-2 w-full py-2.5 rounded-xl bg-red-500/10 hover:bg-red-500 text-red-400 hover:text-white transition-all text-xs font-semibold">
                  <LogOut size={14} /> Sign Out
                </button>
              </div>
            </div>
          </div>
        </header>

        {/* Page content */}
        <main className="flex-1 overflow-auto p-6 relative">
          {children}

          {/* Global AI Chatbot */}
          <AIChatbot />
        </main>
      </div>
    </div>
  );
}
